import os
os.environ["HF_ENDPOINT"] = "https://hf-mirror.com"
os.environ["TRANSFORMERS_VERBOSITY"] = "error"

import torch
import warnings
warnings.filterwarnings('ignore')

# 设备检测
device = "cuda" if torch.cuda.is_available() else "cpu"
print(f"✅ 使用设备: {device}")
if torch.cuda.is_available():
    print(f"✅ CUDA 版本: {torch.version.cuda}")

# 超参数
# MODEL_NAME = "google/bert_uncased_L-2_H-128_A-2"
# MODEL_NAME = "uer/roberta-base-finetuned-chinanews-chinese"
# NUM_VIRTUAL_TOKENS = 4
# NUM_EPOCHS = 3
# MAX_SEQ_LEN = 128
# OUTPUT_DIR = "./peft_bert_final"



# ===================== 修复 1：换英文模型 =====================
MODEL_NAME = "bert-base-uncased"
NUM_VIRTUAL_TOKENS = 8  # 从4→8
NUM_EPOCHS = 3
MAX_SEQ_LEN = 128
OUTPUT_DIR = "./peft_bert_good"





# 分词器 + 模型
from transformers import AutoModelForSequenceClassification, AutoTokenizer
tokenizer = AutoTokenizer.from_pretrained(MODEL_NAME)
base_model = AutoModelForSequenceClassification.from_pretrained(
    MODEL_NAME, 
    num_labels=2,
    ignore_mismatched_sizes=True  # 加上这一行！
).to(device)


# PEFT 配置
from peft import get_peft_model, PromptTuningConfig, TaskType, PromptTuningInit
peft_config = PromptTuningConfig(
    task_type=TaskType.SEQ_CLS,
    prompt_tuning_init=PromptTuningInit.RANDOM,
    num_virtual_tokens=NUM_VIRTUAL_TOKENS,
    tokenizer_name_or_path=MODEL_NAME
)
peft_model = get_peft_model(base_model, peft_config)
peft_model.print_trainable_parameters()

# 数据处理
from datasets import load_dataset
def tokenize_func(examples):
    return tokenizer(examples["text"], truncation=True, max_length=MAX_SEQ_LEN)

dataset = load_dataset("imdb")
tokenized_data = dataset.map(tokenize_func, batched=True)
# ===================== 修复 2：多给点数据 =====================
train_data = tokenized_data["train"].shuffle(seed=42).select(range(2000))
test_data = tokenized_data["test"].shuffle(seed=42).select(range(500))

# 训练器
from transformers import TrainingArguments, Trainer, DataCollatorWithPadding
training_args = TrainingArguments(
    output_dir=OUTPUT_DIR,
    per_device_train_batch_size=8,
    per_device_eval_batch_size=8,
    # learning_rate=0.01,
    learning_rate=3e-3, 
    num_train_epochs=NUM_EPOCHS,
    logging_steps=10,
    fp16=False,
    use_cpu=False,
    report_to="none",
    dataloader_num_workers=0,
)

trainer = Trainer(
    model=peft_model,
    args=training_args,
    train_dataset=train_data,
    eval_dataset=test_data,
    data_collator=DataCollatorWithPadding(tokenizer=tokenizer),
)

# 开始训练
print("\n🚀 开始训练...")
trainer.train()

# 保存与推理
peft_model.save_pretrained(OUTPUT_DIR)
from peft import PeftModel
loaded_model = PeftModel.from_pretrained(base_model, OUTPUT_DIR).to(device)

# 测试
print("\n========== 测试结果 ==========")
# test_texts = [
#     "This movie is amazing! I love it so much!",
#     "Terrible film, waste of time."
# ]

# test_texts = [
#     "这电影太好看了",
#     "浪费时间，一点都不好。"
# ]




test_texts = [
    # 中文影评
    "这电影太好看了，全程无尿点",
    "浪费时间，一点都不好看",
    "剧情精彩，演员演技全程在线",
    "剧情拖沓乏味，看得昏昏欲睡",
    "画面唯美，故事温暖治愈，非常推荐",
    "逻辑混乱，结局仓促，完全不值票价",
    "中规中矩的一部片子，不好也不坏",
    "配乐超加分，代入感极强，年度佳片",
    "台词尴尬，特效廉价，观影体验很差",
    "题材新颖，立意深刻，值得静下心观看",
    # 英文影评
    "This movie is fantastic and totally worth watching",
    "It’s boring and a complete waste of time",
    "The plot is exciting and the acting is perfect",
    "The story is dull and the characters are flat",
    "Great visuals and a warm, touching story",
    "Full of plot holes and a terrible ending",
    "It is an average film with both pros and cons",
    "Amazing soundtrack and deeply resonant content",
    "Awful lines and low-quality special effects",
    "Creative theme and thought-provoking core"
]



for text in test_texts:
    inputs = tokenizer(text, return_tensors="pt", truncation=True, max_length=MAX_SEQ_LEN).to(device)
    with torch.no_grad():
        pred = torch.argmax(loaded_model(**inputs).logits, dim=1).item()
    print(f"文本: {text}")
    print(f"情感: {'正面' if pred==1 else '负面'}\n")




# 训练完后，主动评估测试集
eval_results = trainer.evaluate()
print("\n========== 测试集评估结果 ==========")
print(eval_results)





